class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  StreamSubscription? _linkSubscription;
  String? _initialLink;
  String? _latestLink;

  @override
  void initState() {
    super.initState();
    _initDeepLinks();
  }

  Future<void> _initDeepLinks() async {
    await _handleInitialLink();
    _handleIncomingLinks();
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        setState(() {
          _initialLink = initialLink;
        });
        _processDeepLink(initialLink);
      }
    } on PlatformException catch (e) {
      print('Failed to get initial link: ${e.message}');
    } on FormatException catch (e) {
      print('Invalid link format: ${e.message}');
    }
  }

  void _handleIncomingLinks() {
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          setState(() {
            _latestLink = link;
          });
          _processDeepLink(link);
        }
      },
      onError: (err) {
        print('Error handling incoming link: $err');
      },
    );
  }

  void _processDeepLink(String link) {
    final uri = Uri.parse(link);

    if (uri.scheme != 'myapp') {
      print('Invalid scheme: ${uri.scheme}');
      return;
    }

    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    if (pathSegments.isEmpty) {
      _navigateToHome();
      return;
    }

    final route = pathSegments[0];

    switch (route) {
      case 'profile':
        _handleProfileRoute(pathSegments, queryParams);
        break;
      case 'payment':
        _handlePaymentRoute(pathSegments, queryParams);
        break;
      default:
        print('Unknown route: $route');
        _navigateToHome();
    }
  }

  void _handleProfileRoute(List<String> pathSegments, Map<String, String> queryParams) {
    String? userId;
    String? tab;

    if (pathSegments.length > 1) {
      userId = pathSegments[1];
    }

    if (queryParams.containsKey('tab')) {
      tab = queryParams['tab'];
    }

    Navigator.of(context).pushReplacement(
      MaterialPageRoute(
        builder: (context) => ProfileScreen(
          userId: userId,
          tab: tab,
        ),
      ),
    );
  }

  void _handlePaymentRoute(List<String> pathSegments, Map<String, String> queryParams) {
    String? action;
    String? transactionId;
    String? amount;
    String? status;

    if (pathSegments.length > 1) {
      action = pathSegments[1];
    }

    if (queryParams.containsKey('transaction_id')) {
      transactionId = queryParams['transaction_id'];
    }

    if (queryParams.containsKey('amount')) {
      amount = queryParams['amount'];
    }

    if (queryParams.containsKey('status')) {
      status = queryParams['status'];
    }

    Navigator.of(context).pushReplacement(
      MaterialPageRoute(
        builder: (context) => PaymentScreen(
          action: action,
          transactionId: transactionId,
          amount: amount,
          status: status,
        ),
      ),
    );
  }

  void _navigateToHome() {
    Navigator.of(context).pushReplacement(
      MaterialPageRoute(builder: (context) => HomeScreen()),
    );
  }

  @override
